import { useDelete2, getList2QueryKey } from "@/api/category/category";

export function useDeleteCategory() {
  const queryClient = useQueryClient();
  const navigate = useNavigate();

  const mutation = useDelete2({
    mutation: {
      onSuccess: () => {
        void queryClient.invalidateQueries({
          queryKey: getList2QueryKey(),
        });
        void navigate({ to: "/categories" });
      },
    },
  });

  function deleteCategory(id: string, version: number) {
    mutation.mutate({ id, data: { version } });
  }

  return {
    deleteCategory,
    isDeleting: mutation.isPending,
    error: mutation.error,
  };
}

import { useQueryClient } from "@tanstack/react-query";
import { useNavigate } from "@tanstack/react-router";
import { useCreate2, getList2QueryKey } from "@/api/category/category";

interface CreateCategoryInput {
  readonly name: string;
  readonly sortOrder: number;
  readonly parentCategoryId?: string;
}

export function useCreateCategory() {
  const queryClient = useQueryClient();
  const navigate = useNavigate();

  const mutation = useCreate2({
    mutation: {
      onSuccess: () => {
        void queryClient.invalidateQueries({
          queryKey: getList2QueryKey(),
        });
        void navigate({ to: "/categories" });
      },
    },
  });

  function createCategory(input: CreateCategoryInput) {
    mutation.mutate({
      data: {
        name: input.name,
        sortOrder: input.sortOrder,
        ...(input.parentCategoryId !== undefined && {
          parentCategoryId: input.parentCategoryId,
        }),
      },
    });
  }

  return {
    createCategory,
    isCreating: mutation.isPending,
    error: mutation.error,
  };
}

import { useList2 } from "@/api/category/category";
import type { CategorySummaryResponse } from "@/api/openAPIDefinition.schemas";

export function useCategoryList(page: number = 0, size: number = 20) {
  const query = useList2({
    param: {},
    pageable: { page, size, sort: ["sortOrder,asc"] },
  });

  return {
    categories: (query.data?.data?.content ?? []) as CategorySummaryResponse[],
    totalPages: query.data?.data?.totalPages ?? 0,
    totalElements: query.data?.data?.totalElements ?? 0,
    isLoading: query.isLoading,
    error: query.error,
  };
}

import { useQueryClient } from "@tanstack/react-query";
import { useNavigate } from "@tanstack/react-router";
import {
  useUpdate2,
  getList2QueryKey,
  getFindById2QueryKey,
} from "@/api/category/category";

interface UpdateCategoryInput {
  readonly name: string;
  readonly sortOrder: number;
  readonly version: number;
}

export function useUpdateCategory(id: string) {
  const queryClient = useQueryClient();
  const navigate = useNavigate();

  const mutation = useUpdate2({
    mutation: {
      onSuccess: () => {
        void queryClient.invalidateQueries({
          queryKey: getList2QueryKey(),
        });
        void queryClient.invalidateQueries({
          queryKey: getFindById2QueryKey(id),
        });
        void navigate({ to: "/categories/$id", params: { id } });
      },
    },
  });

  function updateCategory(input: UpdateCategoryInput) {
    mutation.mutate({
      id,
      data: {
        name: input.name,
        sortOrder: input.sortOrder,
        version: input.version,
      },
    });
  }

  return {
    updateCategory,
    isUpdating: mutation.isPending,
    error: mutation.error,
  };
}

