import { useState } from "react";
import { Link } from "@tanstack/react-router";
import { Button } from "@/components/ui/button";
import { ConfirmDialog } from "@/components/confirm-dialog";
import { ErrorMessage } from "@/components/error-message";
import { toError } from "@/lib/utils";
import { useCategory } from "@/features/category/hooks/use-category";
import { useDeleteCategory } from "@/features/category/hooks/use-delete-category";

interface CategoryDetailProps {
  readonly id: string;
}

export function CategoryDetail({ id }: CategoryDetailProps) {
  const { category, isLoading, error, refetch } = useCategory(id);
  const { deleteCategory, isDeleting, error: deleteError } = useDeleteCategory();
  const [isDialogOpen, setIsDialogOpen] = useState(false);

  if (isLoading) {
    return (
      <div className="space-y-4">
        <div className="h-8 w-48 animate-pulse rounded bg-muted" />
        <div className="h-6 w-32 animate-pulse rounded bg-muted" />
      </div>
    );
  }

  if (error) {
    return <ErrorMessage error={toError(error)} onRetry={() => { void refetch(); }} />;
  }

  if (category === null) {
    return <ErrorMessage error={new Error("カテゴリが見つかりません")} />;
  }

  function handleDeleteClick() {
    setIsDialogOpen(true);
  }

  function handleConfirmDelete() {
    if (category === null) {
      return;
    }
    deleteCategory(category.id, category.version);
    setIsDialogOpen(false);
  }

  return (
    <div className="space-y-6">
      {deleteError !== null && deleteError !== undefined && (
        <ErrorMessage error={toError(deleteError)} />
      )}

      <div className="space-y-4">
        {category.ancestors.length > 0 && (
          <nav className="flex items-center gap-1 text-sm text-muted-foreground">
            {category.ancestors.map((ancestor, index) => (
              <span key={ancestor.id} className="flex items-center gap-1">
                {index > 0 && <span>/</span>}
                <Link
                  to="/categories/$id"
                  params={{ id: ancestor.id ?? "" }}
                  className="hover:underline"
                >
                  {ancestor.name}
                </Link>
              </span>
            ))}
            <span>/</span>
            <span className="font-medium text-foreground">{category.name}</span>
          </nav>
        )}

        <dl className="grid grid-cols-[auto_1fr] gap-x-6 gap-y-3">
          <dt className="text-sm font-medium text-muted-foreground">
            カテゴリ名
          </dt>
          <dd>{category.name}</dd>

          <dt className="text-sm font-medium text-muted-foreground">並び順</dt>
          <dd>{category.sortOrder}</dd>

          <dt className="text-sm font-medium text-muted-foreground">
            バージョン
          </dt>
          <dd>{category.version}</dd>
        </dl>
      </div>

      <div className="flex gap-2">
        <Button asChild>
          <Link to="/categories/$id/edit" params={{ id }}>
            編集
          </Link>
        </Button>
        <Button variant="destructive" onClick={handleDeleteClick}>
          削除
        </Button>
      </div>

      <ConfirmDialog
        isOpen={isDialogOpen}
        onClose={() => { setIsDialogOpen(false); }}
        onConfirm={handleConfirmDelete}
        title="カテゴリを削除"
        message={`「${category.name}」を削除しますか？この操作は取り消せません。`}
        confirmLabel="削除する"
        isLoading={isDeleting}
      />
    </div>
  );
}

import { useState } from "react";
import { Link } from "@tanstack/react-router";
import { Button } from "@/components/ui/button";
import { ErrorMessage } from "@/components/error-message";
import { toError } from "@/lib/utils";
import { useCreateCategory } from "@/features/category/hooks/use-create-category";

export function CategoryCreateForm() {
  const { createCategory, isCreating, error } = useCreateCategory();
  const [name, setName] = useState("");
  const [sortOrder, setSortOrder] = useState(0);

  function handleSubmit(event: React.FormEvent<HTMLFormElement>) {
    event.preventDefault();
    createCategory({ name, sortOrder });
  }

  return (
    <form onSubmit={handleSubmit} className="max-w-md space-y-4">
      {error !== null && error !== undefined && (
        <ErrorMessage error={toError(error)} />
      )}

      <div className="space-y-2">
        <label htmlFor="name" className="text-sm font-medium">
          カテゴリ名
        </label>
        <input
          id="name"
          type="text"
          value={name}
          onChange={(e) => {
            setName(e.target.value);
          }}
          required
          maxLength={50}
          className="w-full rounded-md border px-3 py-2"
          placeholder="カテゴリ名を入力"
        />
      </div>

      <div className="space-y-2">
        <label htmlFor="sortOrder" className="text-sm font-medium">
          並び順
        </label>
        <input
          id="sortOrder"
          type="number"
          value={sortOrder}
          onChange={(e) => {
            setSortOrder(Number(e.target.value));
          }}
          required
          min={0}
          className="w-full rounded-md border px-3 py-2"
        />
      </div>

      <div className="flex gap-2">
        <Button type="submit" disabled={isCreating}>
          {isCreating ? "作成中..." : "作成"}
        </Button>
        <Button asChild variant="outline">
          <Link to="/categories">キャンセル</Link>
        </Button>
      </div>
    </form>
  );
}

