import { createFileRoute } from "@tanstack/react-router";
import { Link } from "@tanstack/react-router";
import { Button } from "@/components/ui/button";
import { CategoryList } from "@/features/category/components/category-list";

export const Route = createFileRoute("/categories")({
  component: CategoriesPage,
});

function CategoriesPage() {
  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold">カテゴリ管理</h1>
        <Button asChild>
          <Link to="/categories/new">新規作成</Link>
        </Button>
      </div>
      <CategoryList />
    </div>
  );
}

import { createFileRoute } from "@tanstack/react-router";
import { CategoryCreateForm } from "@/features/category/components/category-create-form";

export const Route = createFileRoute("/categories_/new")({
  component: CategoryNewPage,
});

function CategoryNewPage() {
  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">カテゴリ作成</h1>
      <CategoryCreateForm />
    </div>
  );
}

import { createFileRoute } from "@tanstack/react-router";
import { CategoryDetail } from "@/features/category/components/category-detail";

export const Route = createFileRoute("/categories_/$id")({
  component: CategoryDetailPage,
});

function CategoryDetailPage() {
  const { id } = Route.useParams();

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">カテゴリ詳細</h1>
      <CategoryDetail id={id} />
    </div>
  );
}

