import { useList2 } from "@/api/category/category";
import type { CategorySummaryResponse } from "@/api/openAPIDefinition.schemas";

interface CategoryOption {
  readonly id: string;
  readonly name: string;
}

export function useCategoryOptions() {
  const query = useList2({
    param: {},
    pageable: { page: 0, size: 1000, sort: ["sortOrder,asc"] },
  });

  const categories = (query.data?.data?.content ?? []) as CategorySummaryResponse[];
  const options: CategoryOption[] = categories
    .filter((c): c is CategorySummaryResponse & { id: string; name: string } =>
      c.id !== undefined && c.name !== undefined,
    )
    .map((c) => ({ id: c.id, name: c.name }));

  return {
    options,
    isLoading: query.isLoading,
    error: query.error,
  };
}

import { useQueryClient } from "@tanstack/react-query";
import {
  useMove,
  getList2QueryKey,
  getFindById2QueryKey,
} from "@/api/category/category";

export function useMoveCategory(id: string) {
  const queryClient = useQueryClient();

  const mutation = useMove({
    mutation: {
      onSuccess: () => {
        void queryClient.invalidateQueries({
          queryKey: getList2QueryKey(),
        });
        void queryClient.invalidateQueries({
          queryKey: getFindById2QueryKey(id),
        });
      },
    },
  });

  function moveCategory(newParentCategoryId: string | null, version: number) {
    mutation.mutate({
      id,
      data: {
        version,
        ...(newParentCategoryId !== null && { newParentCategoryId }),
      },
    });
  }

  return {
    moveCategory,
    isMoving: mutation.isPending,
    isSuccess: mutation.isSuccess,
    error: mutation.error,
    reset: mutation.reset,
  };
}

