import { describe, expect, it, vi, beforeEach } from "vite-plus/test";
import { renderHook } from "@testing-library/react";
import { createElement } from "react";
import type { ReactNode } from "react";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { useCategoryOptions } from "@/features/category/hooks/use-category-options";

vi.mock("@/api/category/category", () => ({
  useList2: vi.fn(),
}));

import { useList2 } from "@/api/category/category";

function createWrapper() {
  const queryClient = new QueryClient({
    defaultOptions: { queries: { retry: false } },
  });

  return function Wrapper({ children }: { readonly children: ReactNode }) {
    return createElement(QueryClientProvider, { client: queryClient }, children);
  };
}

describe("useCategoryOptions", () => {
  beforeEach(() => {
    vi.resetAllMocks();
  });

  it("ロード中は空の options を返す", () => {
    vi.mocked(useList2).mockReturnValue({
      data: undefined,
      isLoading: true,
      error: null,
    } as ReturnType<typeof useList2>);

    const { result } = renderHook(() => useCategoryOptions(), {
      wrapper: createWrapper(),
    });

    expect(result.current.isLoading).toBe(true);
    expect(result.current.options).toEqual([]);
  });

  it("取得成功時に options を返す", () => {
    vi.mocked(useList2).mockReturnValue({
      data: {
        data: {
          content: [
            { id: "1", name: "カテゴリA", sortOrder: 0 },
            { id: "2", name: "カテゴリB", sortOrder: 1 },
          ],
        },
        status: 200,
        headers: new Headers(),
      },
      isLoading: false,
      error: null,
    } as unknown as ReturnType<typeof useList2>);

    const { result } = renderHook(() => useCategoryOptions(), {
      wrapper: createWrapper(),
    });

    expect(result.current.options).toEqual([
      { id: "1", name: "カテゴリA" },
      { id: "2", name: "カテゴリB" },
    ]);
  });
});

