import { Link } from "@tanstack/react-router";
import { Button } from "@/components/ui/button";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { ErrorMessage } from "@/components/error-message";
import { EmptyState } from "@/components/empty-state";
import { toError } from "@/lib/utils";
import { useCategoryList } from "@/features/category/hooks/use-category-list";
import { CategoryListSkeleton } from "@/features/category/components/category-list-skeleton";

export function CategoryList() {
  const { categories, isLoading, error } = useCategoryList();

  if (isLoading) {
    return <CategoryListSkeleton />;
  }

  if (error) {
    return <ErrorMessage error={toError(error)} />;
  }

  if (categories.length === 0) {
    return <EmptyState message="カテゴリがありません" />;
  }

  return (
    <Table>
      <TableHeader>
        <TableRow>
          <TableHead>カテゴリ名</TableHead>
          <TableHead className="w-32">並び順</TableHead>
          <TableHead className="w-24" />
        </TableRow>
      </TableHeader>
      <TableBody>
        {categories.map((category) => (
          <TableRow key={category.id}>
            <TableCell>
              <Link
                to="/categories/$id"
                params={{ id: category.id ?? "" }}
                className="font-medium hover:underline"
              >
                {category.name}
              </Link>
            </TableCell>
            <TableCell>{category.sortOrder}</TableCell>
            <TableCell>
              <Button asChild variant="ghost" size="sm">
                <Link to="/categories/$id" params={{ id: category.id ?? "" }}>
                  詳細
                </Link>
              </Button>
            </TableCell>
          </TableRow>
        ))}
      </TableBody>
    </Table>
  );
}

