import { useState } from "react";
import { Link } from "@tanstack/react-router";
import { ChevronRight, ChevronDown } from "lucide-react";
import { Button } from "@/components/ui/button";
import { TableCell, TableRow } from "@/components/ui/table";
import { useCategoryChildren } from "@/features/category/hooks/use-category-children";

interface CategoryRowProps {
  readonly id: string;
  readonly name: string;
  readonly sortOrder: number;
}

export function CategoryRow({ id, name, sortOrder }: CategoryRowProps) {
  const [isExpanded, setIsExpanded] = useState(false);

  return (
    <>
      <TableRow>
        <TableCell>
          <div className="flex items-center gap-1">
            <button
              type="button"
              onClick={() => {
                setIsExpanded((prev) => !prev);
              }}
              className="rounded p-0.5 hover:bg-muted"
              aria-label={isExpanded ? "折りたたむ" : "展開する"}
            >
              {isExpanded ? (
                <ChevronDown className="size-4" />
              ) : (
                <ChevronRight className="size-4" />
              )}
            </button>
            <Link
              to="/categories/$id"
              params={{ id }}
              className="font-medium hover:underline"
            >
              {name}
            </Link>
          </div>
        </TableCell>
        <TableCell>{sortOrder}</TableCell>
        <TableCell>
          <Button asChild variant="ghost" size="sm">
            <Link to="/categories/$id" params={{ id }}>
              詳細
            </Link>
          </Button>
        </TableCell>
      </TableRow>
      {isExpanded && <ChildrenRows parentId={id} />}
    </>
  );
}

interface ChildrenRowsProps {
  readonly parentId: string;
}

function ChildrenRows({ parentId }: ChildrenRowsProps) {
  const { children, isLoading } = useCategoryChildren(parentId);

  if (isLoading) {
    return (
      <TableRow>
        <TableCell colSpan={3} className="pl-10">
          <div className="h-6 w-32 animate-pulse rounded bg-muted" />
        </TableCell>
      </TableRow>
    );
  }

  if (children.length === 0) {
    return (
      <TableRow>
        <TableCell colSpan={3} className="pl-10 text-sm text-muted-foreground">
          子カテゴリなし
        </TableCell>
      </TableRow>
    );
  }

  return (
    <>
      {children.map((child) => (
        <TableRow key={child.id} className="bg-muted/30">
          <TableCell className="pl-10">
            <Link
              to="/categories/$id"
              params={{ id: child.id ?? "" }}
              className="text-sm hover:underline"
            >
              {child.name}
            </Link>
          </TableCell>
          <TableCell className="text-sm">{child.sortOrder}</TableCell>
          <TableCell>
            <Button asChild variant="ghost" size="xs">
              <Link to="/categories/$id" params={{ id: child.id ?? "" }}>
                詳細
              </Link>
            </Button>
          </TableCell>
        </TableRow>
      ))}
    </>
  );
}

