import { useState } from "react";
import { Link } from "@tanstack/react-router";
import { ChevronRight, ChevronDown } from "lucide-react";
import { useCategoryChildren } from "@/features/category/hooks/use-category-children";

interface CategoryTreeNodeProps {
  readonly id: string;
  readonly name: string;
  readonly sortOrder: number;
  readonly depth: number;
}

export function CategoryTreeNode({
  id,
  name,
  sortOrder,
  depth,
}: CategoryTreeNodeProps) {
  const [isExpanded, setIsExpanded] = useState(false);

  return (
    <li>
      <div
        className="flex items-center gap-1 rounded-md px-2 py-1.5 hover:bg-muted"
        style={{ paddingLeft: `${String(depth * 1.25 + 0.5)}rem` }}
      >
        <button
          type="button"
          onClick={() => {
            setIsExpanded((prev) => !prev);
          }}
          className="flex size-5 items-center justify-center rounded hover:bg-muted-foreground/10"
          aria-label={isExpanded ? "折りたたむ" : "展開する"}
        >
          {isExpanded ? (
            <ChevronDown className="size-3.5" />
          ) : (
            <ChevronRight className="size-3.5" />
          )}
        </button>
        <Link
          to="/categories/$id"
          params={{ id }}
          className="flex-1 text-sm font-medium hover:underline"
        >
          {name}
        </Link>
        <span className="text-xs text-muted-foreground">#{sortOrder}</span>
      </div>
      {isExpanded && <ChildNodes parentId={id} depth={depth + 1} />}
    </li>
  );
}

interface ChildNodesProps {
  readonly parentId: string;
  readonly depth: number;
}

function ChildNodes({ parentId, depth }: ChildNodesProps) {
  const { children, isLoading } = useCategoryChildren(parentId);

  if (isLoading) {
    return (
      <div
        className="py-1"
        style={{ paddingLeft: `${String(depth * 1.25 + 0.5)}rem` }}
      >
        <div className="h-5 w-28 animate-pulse rounded bg-muted" />
      </div>
    );
  }

  if (children.length === 0) {
    return (
      <div
        className="py-1 text-xs text-muted-foreground"
        style={{ paddingLeft: `${String(depth * 1.25 + 1.75)}rem` }}
      >
        子カテゴリなし
      </div>
    );
  }

  return (
    <ul>
      {children.map((child) => (
        <CategoryTreeNode
          key={child.id}
          id={child.id ?? ""}
          name={child.name ?? ""}
          sortOrder={child.sortOrder ?? 0}
          depth={depth}
        />
      ))}
    </ul>
  );
}

