export const PRODUCT_STATUS = {
  DRAFT: "DRAFT",
  PUBLISHED: "PUBLISHED",
  ARCHIVED: "ARCHIVED",
} as const;

export type ProductStatus =
  (typeof PRODUCT_STATUS)[keyof typeof PRODUCT_STATUS];

export const STATUS_LABELS: Record<ProductStatus, string> = {
  DRAFT: "下書き",
  PUBLISHED: "公開",
  ARCHIVED: "アーカイブ",
};

export const STATUS_COLORS: Record<ProductStatus, string> = {
  DRAFT: "bg-muted text-muted-foreground",
  PUBLISHED: "bg-emerald-100 text-emerald-700",
  ARCHIVED: "bg-zinc-100 text-zinc-500",
};

import { useList } from "@/api/product/product";
import type { ProductSummaryResponse } from "@/api/openAPIDefinition.schemas";

export function useProductList(
  page: number = 0,
  size: number = 20,
  categoryId?: string,
  status?: string,
) {
  const query = useList({
    param: {
      ...(categoryId !== undefined && { categoryId }),
      ...(status !== undefined && { status }),
    },
    pageable: { page, size, sort: ["name,asc"] },
  });

  return {
    products: (query.data?.data?.content ?? []) as ProductSummaryResponse[],
    totalPages: query.data?.data?.totalPages ?? 0,
    totalElements: query.data?.data?.totalElements ?? 0,
    isLoading: query.isLoading,
    error: query.error,
  };
}

import { useFindById } from "@/api/product/product";
import type { ProductDetailResponse } from "@/api/openAPIDefinition.schemas";

interface ProductDetail {
  readonly id: string;
  readonly name: string;
  readonly description: string;
  readonly categoryId: string;
  readonly sku: string;
  readonly status: string;
  readonly version: number;
}

function toDetail(data: ProductDetailResponse): ProductDetail {
  return {
    id: data.id ?? "",
    name: data.name ?? "",
    description: data.description ?? "",
    categoryId: data.categoryId ?? "",
    sku: data.sku ?? "",
    status: data.status ?? "DRAFT",
    version: data.version ?? 0,
  };
}

export function useProduct(id: string) {
  const query = useFindById(id);

  return {
    product: query.data?.data !== undefined ? toDetail(query.data.data) : null,
    isLoading: query.isLoading,
    error: query.error,
    refetch: query.refetch,
  };
}

import { useQueryClient } from "@tanstack/react-query";
import { useNavigate } from "@tanstack/react-router";
import { useCreate, getListQueryKey } from "@/api/product/product";

interface CreateProductInput {
  readonly name: string;
  readonly description: string;
  readonly categoryId: string;
  readonly sku: string;
}

export function useCreateProduct() {
  const queryClient = useQueryClient();
  const navigate = useNavigate();

  const mutation = useCreate({
    mutation: {
      onSuccess: () => {
        void queryClient.invalidateQueries({ queryKey: getListQueryKey() });
        void navigate({ to: "/products" });
      },
    },
  });

  function createProduct(input: CreateProductInput) {
    mutation.mutate({ data: input });
  }

  return {
    createProduct,
    isCreating: mutation.isPending,
    error: mutation.error,
  };
}

import { useQueryClient } from "@tanstack/react-query";
import { useNavigate } from "@tanstack/react-router";
import {
  useUpdate,
  getListQueryKey,
  getFindByIdQueryKey,
} from "@/api/product/product";

interface UpdateProductInput {
  readonly name: string;
  readonly description: string;
  readonly categoryId: string;
  readonly version: number;
}

export function useUpdateProduct(id: string) {
  const queryClient = useQueryClient();
  const navigate = useNavigate();

  const mutation = useUpdate({
    mutation: {
      onSuccess: () => {
        void queryClient.invalidateQueries({ queryKey: getListQueryKey() });
        void queryClient.invalidateQueries({
          queryKey: getFindByIdQueryKey(id),
        });
        void navigate({ to: "/products/$id", params: { id } });
      },
    },
  });

  function updateProduct(input: UpdateProductInput) {
    mutation.mutate({ id, data: input });
  }

  return {
    updateProduct,
    isUpdating: mutation.isPending,
    error: mutation.error,
  };
}

import { useQueryClient } from "@tanstack/react-query";
import { useNavigate } from "@tanstack/react-router";
import { useDelete, getListQueryKey } from "@/api/product/product";

export function useDeleteProduct() {
  const queryClient = useQueryClient();
  const navigate = useNavigate();

  const mutation = useDelete({
    mutation: {
      onSuccess: () => {
        void queryClient.invalidateQueries({ queryKey: getListQueryKey() });
        void navigate({ to: "/products" });
      },
    },
  });

  function deleteProduct(id: string, version: number) {
    mutation.mutate({ id, data: { version } });
  }

  return {
    deleteProduct,
    isDeleting: mutation.isPending,
    error: mutation.error,
  };
}

import { useQueryClient } from "@tanstack/react-query";
import {
  usePublish,
  useUnpublish,
  useArchive,
  getListQueryKey,
  getFindByIdQueryKey,
} from "@/api/product/product";

export function useProductStatus(id: string) {
  const queryClient = useQueryClient();

  const invalidate = () => {
    void queryClient.invalidateQueries({ queryKey: getListQueryKey() });
    void queryClient.invalidateQueries({ queryKey: getFindByIdQueryKey(id) });
  };

  const publishMutation = usePublish({
    mutation: { onSuccess: invalidate },
  });
  const unpublishMutation = useUnpublish({
    mutation: { onSuccess: invalidate },
  });
  const archiveMutation = useArchive({
    mutation: { onSuccess: invalidate },
  });

  function publishProduct(version: number) {
    publishMutation.mutate({ id, data: { version } });
  }

  function unpublishProduct(version: number) {
    unpublishMutation.mutate({ id, data: { version } });
  }

  function archiveProduct(version: number) {
    archiveMutation.mutate({ id, data: { version } });
  }

  return {
    publishProduct,
    unpublishProduct,
    archiveProduct,
    isPending:
      publishMutation.isPending ||
      unpublishMutation.isPending ||
      archiveMutation.isPending,
    error:
      publishMutation.error ?? unpublishMutation.error ?? archiveMutation.error,
  };
}

