import { cn } from "@/lib/utils";
import {
  STATUS_LABELS,
  STATUS_COLORS,
} from "@/features/product/types/product-status";
import type { ProductStatus } from "@/features/product/types/product-status";

interface StatusBadgeProps {
  readonly status: string;
}

export function StatusBadge({ status }: StatusBadgeProps) {
  const label = STATUS_LABELS[status as ProductStatus] ?? status;
  const color =
    STATUS_COLORS[status as ProductStatus] ?? "bg-muted text-muted-foreground";

  return (
    <span
      className={cn(
        "inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium",
        color,
      )}
    >
      {label}
    </span>
  );
}

import { useState } from "react";
import { Link } from "@tanstack/react-router";
import { Button } from "@/components/ui/button";
import { ConfirmDialog } from "@/components/confirm-dialog";
import { ErrorMessage } from "@/components/error-message";
import { toError } from "@/lib/utils";
import { useProduct } from "@/features/product/hooks/use-product";
import { useDeleteProduct } from "@/features/product/hooks/use-delete-product";
import { useProductStatus } from "@/features/product/hooks/use-product-status";
import { StatusBadge } from "@/features/product/components/status-badge";
import { PRODUCT_STATUS } from "@/features/product/types/product-status";

interface ProductDetailProps {
  readonly id: string;
}

export function ProductDetail({ id }: ProductDetailProps) {
  const { product, isLoading, error, refetch } = useProduct(id);
  const { deleteProduct, isDeleting, error: deleteError } = useDeleteProduct();
  const {
    publishProduct,
    unpublishProduct,
    archiveProduct,
    isPending: isStatusPending,
    error: statusError,
  } = useProductStatus(id);
  const [isDialogOpen, setIsDialogOpen] = useState(false);

  if (isLoading) {
    return (
      <div className="space-y-4">
        <div className="h-8 w-48 animate-pulse rounded bg-muted" />
        <div className="h-6 w-64 animate-pulse rounded bg-muted" />
      </div>
    );
  }

  if (error) {
    return (
      <ErrorMessage
        error={toError(error)}
        onRetry={() => {
          void refetch();
        }}
      />
    );
  }

  if (product === null) {
    return <ErrorMessage error={new Error("商品が見つかりません")} />;
  }

  function handleConfirmDelete() {
    if (product === null) {
      return;
    }
    deleteProduct(product.id, product.version);
    setIsDialogOpen(false);
  }

  return (
    <div className="space-y-6">
      {deleteError !== null && deleteError !== undefined && (
        <ErrorMessage error={toError(deleteError)} />
      )}
      {statusError !== null && statusError !== undefined && (
        <ErrorMessage error={toError(statusError)} />
      )}

      <div className="space-y-4">
        <div className="flex items-center gap-3">
          <h2 className="text-xl font-semibold">{product.name}</h2>
          <StatusBadge status={product.status} />
        </div>

        <dl className="grid grid-cols-[auto_1fr] gap-x-6 gap-y-3">
          <dt className="text-sm font-medium text-muted-foreground">説明</dt>
          <dd>{product.description}</dd>

          <dt className="text-sm font-medium text-muted-foreground">SKU</dt>
          <dd className="font-mono text-sm">{product.sku}</dd>

          <dt className="text-sm font-medium text-muted-foreground">
            カテゴリ ID
          </dt>
          <dd className="font-mono text-sm">{product.categoryId}</dd>

          <dt className="text-sm font-medium text-muted-foreground">
            バージョン
          </dt>
          <dd>{product.version}</dd>
        </dl>
      </div>

      <div className="flex flex-wrap gap-2">
        <Button asChild>
          <Link to="/products/$id/edit" params={{ id }}>
            編集
          </Link>
        </Button>

        {product.status === PRODUCT_STATUS.DRAFT && (
          <Button
            variant="outline"
            onClick={() => {
              publishProduct(product.version);
            }}
            disabled={isStatusPending}
          >
            公開する
          </Button>
        )}
        {product.status === PRODUCT_STATUS.PUBLISHED && (
          <Button
            variant="outline"
            onClick={() => {
              unpublishProduct(product.version);
            }}
            disabled={isStatusPending}
          >
            非公開にする
          </Button>
        )}
        {product.status !== PRODUCT_STATUS.ARCHIVED && (
          <Button
            variant="outline"
            onClick={() => {
              archiveProduct(product.version);
            }}
            disabled={isStatusPending}
          >
            アーカイブ
          </Button>
        )}

        <Button
          variant="destructive"
          onClick={() => {
            setIsDialogOpen(true);
          }}
        >
          削除
        </Button>
      </div>

      <ConfirmDialog
        isOpen={isDialogOpen}
        onClose={() => {
          setIsDialogOpen(false);
        }}
        onConfirm={handleConfirmDelete}
        title="商品を削除"
        message={`「${product.name}」を削除しますか？この操作は取り消せません。`}
        confirmLabel="削除する"
        isLoading={isDeleting}
      />
    </div>
  );
}

