import { useList1 } from "@/api/pricing/pricing";
import type { PricingSummaryResponse } from "@/api/openAPIDefinition.schemas";

export function usePricingList(
  page: number = 0,
  size: number = 20,
  productId?: string,
) {
  const query = useList1({
    param: {
      ...(productId !== undefined && { productId }),
    },
    pageable: { page, size },
  });

  return {
    pricings: (query.data?.data?.content ?? []) as PricingSummaryResponse[],
    totalPages: query.data?.data?.totalPages ?? 0,
    totalElements: query.data?.data?.totalElements ?? 0,
    isLoading: query.isLoading,
    error: query.error,
  };
}

import { useFindById1 } from "@/api/pricing/pricing";
import type { PricingDetailResponse } from "@/api/openAPIDefinition.schemas";

interface PricingDetail {
  readonly id: string;
  readonly productId: string;
  readonly level: string;
  readonly areaCode: string;
  readonly amount: number;
  readonly validFrom: string;
  readonly validTo: string | null;
  readonly version: number;
}

function toDetail(data: PricingDetailResponse): PricingDetail {
  return {
    id: data.id ?? "",
    productId: data.productId ?? "",
    level: data.level ?? "",
    areaCode: data.areaCode ?? "",
    amount: data.amount ?? 0,
    validFrom: data.validFrom ?? "",
    validTo: data.validTo ?? null,
    version: data.version ?? 0,
  };
}

export function usePricing(id: string) {
