import { Link } from "@tanstack/react-router";
import { Button } from "@/components/ui/button";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { ErrorMessage } from "@/components/error-message";
import { EmptyState } from "@/components/empty-state";
import { toError } from "@/lib/utils";
import { usePricingList } from "@/features/pricing/hooks/use-pricing-list";
import { PricingListSkeleton } from "@/features/pricing/components/pricing-list-skeleton";

export function PricingList() {
  const { pricings, isLoading, error } = usePricingList();

  if (isLoading) {
    return <PricingListSkeleton />;
  }

  if (error) {
    return <ErrorMessage error={toError(error)} />;
  }

  if (pricings.length === 0) {
    return <EmptyState message="価格が登録されていません" />;
  }

  return (
    <Table>
      <TableHeader>
        <TableRow>
          <TableHead>商品 ID</TableHead>
          <TableHead>レベル</TableHead>
          <TableHead>エリア</TableHead>
          <TableHead className="text-right">金額</TableHead>
          <TableHead className="w-24" />
        </TableRow>
      </TableHeader>
      <TableBody>
        {pricings.map((pricing) => (
          <TableRow key={pricing.id}>
            <TableCell className="font-mono text-xs">
              {pricing.productId}
            </TableCell>
            <TableCell>{pricing.level}</TableCell>
            <TableCell>{pricing.areaCode}</TableCell>
            <TableCell className="text-right">
              {pricing.amount?.toLocaleString()}
            </TableCell>
            <TableCell>
              <Button asChild variant="ghost" size="sm">
                <Link to="/pricings/$id" params={{ id: pricing.id ?? "" }}>
                  詳細
                </Link>
              </Button>
            </TableCell>
          </TableRow>
        ))}
      </TableBody>
    </Table>
  );
}

export function PricingListSkeleton() {
  return (
    <div className="space-y-3">
      {Array.from({ length: 5 }).map((_, i) => (
        <div
          key={`skeleton-${String(i)}`}
          className="h-12 animate-pulse rounded-md bg-muted"
        />
      ))}
    </div>
  );
}

import { useState } from "react";
import { Link } from "@tanstack/react-router";
import { Button } from "@/components/ui/button";
import { ConfirmDialog } from "@/components/confirm-dialog";
import { ErrorMessage } from "@/components/error-message";
import { toError } from "@/lib/utils";
import { usePricing } from "@/features/pricing/hooks/use-pricing";
import { useDeletePricing } from "@/features/pricing/hooks/use-delete-pricing";

interface PricingDetailProps {
  readonly id: string;
}

export function PricingDetail({ id }: PricingDetailProps) {
  const { pricing, isLoading, error, refetch } = usePricing(id);
  const { deletePricing, isDeleting, error: deleteError } = useDeletePricing();
  const [isDialogOpen, setIsDialogOpen] = useState(false);

  if (isLoading) {
    return (
      <div className="space-y-4">
        <div className="h-8 w-48 animate-pulse rounded bg-muted" />
        <div className="h-6 w-64 animate-pulse rounded bg-muted" />
      </div>
    );
  }

  if (error) {
    return (
      <ErrorMessage
        error={toError(error)}
        onRetry={() => {
          void refetch();
        }}
      />
    );
  }

  if (pricing === null) {
    return <ErrorMessage error={new Error("価格が見つかりません")} />;
  }

  function handleConfirmDelete() {
    if (pricing === null) {
      return;
    }
    deletePricing(pricing.id, pricing.version);
    setIsDialogOpen(false);
  }

  return (
    <div className="space-y-6">
      {deleteError !== null && deleteError !== undefined && (
        <ErrorMessage error={toError(deleteError)} />
      )}

      <dl className="grid grid-cols-[auto_1fr] gap-x-6 gap-y-3">
        <dt className="text-sm font-medium text-muted-foreground">商品 ID</dt>
        <dd className="font-mono text-sm">{pricing.productId}</dd>

        <dt className="text-sm font-medium text-muted-foreground">レベル</dt>
        <dd>{pricing.level}</dd>

        <dt className="text-sm font-medium text-muted-foreground">エリアコード</dt>
        <dd>{pricing.areaCode}</dd>

        <dt className="text-sm font-medium text-muted-foreground">金額</dt>
        <dd className="text-lg font-semibold">
          ¥{pricing.amount.toLocaleString()}
        </dd>

        <dt className="text-sm font-medium text-muted-foreground">有効開始</dt>
        <dd>{pricing.validFrom}</dd>

        <dt className="text-sm font-medium text-muted-foreground">有効終了</dt>
        <dd>{pricing.validTo ?? "—"}</dd>

        <dt className="text-sm font-medium text-muted-foreground">バージョン</dt>
        <dd>{pricing.version}</dd>
      </dl>

      <div className="flex gap-2">
        <Button asChild>
          <Link to="/pricings/$id/edit" params={{ id }}>
            編集
          </Link>
        </Button>
        <Button
          variant="destructive"
          onClick={() => {
            setIsDialogOpen(true);
          }}
        >
          削除
        </Button>
      </div>

      <ConfirmDialog
        isOpen={isDialogOpen}
        onClose={() => {
          setIsDialogOpen(false);
        }}
        onConfirm={handleConfirmDelete}
        title="価格を削除"
        message="この価格を削除しますか？この操作は取り消せません。"
        confirmLabel="削除する"
        isLoading={isDeleting}
      />
    </div>
  );
}

import { useState } from "react";
import { Link } from "@tanstack/react-router";
import { Button } from "@/components/ui/button";
import { ErrorMessage } from "@/components/error-message";
import { toError } from "@/lib/utils";
import { useCreatePricing } from "@/features/pricing/hooks/use-create-pricing";

export function PricingCreateForm() {
  const { createPricing, isCreating, error } = useCreatePricing();
  const [productId, setProductId] = useState("");
  const [level, setLevel] = useState("");
  const [areaCode, setAreaCode] = useState("");
  const [amount, setAmount] = useState("");
  const [validFrom, setValidFrom] = useState("");
  const [validTo, setValidTo] = useState("");

  function handleSubmit(event: React.FormEvent<HTMLFormElement>) {
    event.preventDefault();
    createPricing({
      productId,
      level,
      areaCode,
      amount: Number(amount),
      validFrom: new Date(validFrom).toISOString(),
      ...(validTo !== "" && { validTo: new Date(validTo).toISOString() }),
    });
  }

  return (
    <form onSubmit={handleSubmit} className="max-w-lg space-y-4">
      {error !== null && error !== undefined && (
        <ErrorMessage error={toError(error)} />
      )}

      <div className="space-y-2">
        <label htmlFor="productId" className="text-sm font-medium">
          商品 ID
        </label>
        <input
          id="productId"
          type="text"
          value={productId}
          onChange={(e) => {
            setProductId(e.target.value);
          }}
          required
          className="w-full rounded-md border px-3 py-2 font-mono"
          placeholder="商品IDを入力"
        />
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div className="space-y-2">
          <label htmlFor="level" className="text-sm font-medium">
            レベル
          </label>
          <input
            id="level"
            type="text"
            value={level}
            onChange={(e) => {
              setLevel(e.target.value);
            }}
            required
            className="w-full rounded-md border px-3 py-2"
            placeholder="STANDARD"
          />
        </div>

        <div className="space-y-2">
          <label htmlFor="areaCode" className="text-sm font-medium">
            エリアコード
          </label>
          <input
            id="areaCode"
            type="text"
            value={areaCode}
            onChange={(e) => {
              setAreaCode(e.target.value);
            }}
            required
            className="w-full rounded-md border px-3 py-2"
            placeholder="JP-13"
          />
        </div>
      </div>

      <div className="space-y-2">
        <label htmlFor="amount" className="text-sm font-medium">
          金額
        </label>
        <input
          id="amount"
          type="number"
          value={amount}
          onChange={(e) => {
            setAmount(e.target.value);
          }}
          required
          min={1}
          step="0.01"
          className="w-full rounded-md border px-3 py-2"
          placeholder="1000"
        />
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div className="space-y-2">
          <label htmlFor="validFrom" className="text-sm font-medium">
            有効開始日時
          </label>
          <input
            id="validFrom"
            type="datetime-local"
            value={validFrom}
            onChange={(e) => {
              setValidFrom(e.target.value);
            }}
            required
            className="w-full rounded-md border px-3 py-2"
          />
        </div>

        <div className="space-y-2">
          <label htmlFor="validTo" className="text-sm font-medium">
            有効終了日時（任意）
          </label>
          <input
            id="validTo"
            type="datetime-local"
            value={validTo}
            onChange={(e) => {
              setValidTo(e.target.value);
            }}
            className="w-full rounded-md border px-3 py-2"
          />
        </div>
      </div>

      <div className="flex gap-2">
        <Button type="submit" disabled={isCreating}>
          {isCreating ? "作成中..." : "作成"}
        </Button>
        <Button asChild variant="outline">
          <Link to="/pricings">キャンセル</Link>
        </Button>
      </div>
    </form>
  );
}

import { useState } from "react";
import { Link } from "@tanstack/react-router";
