interface PricingEditFormProps {
  readonly id: string;
}

function toDatetimeLocal(isoString: string): string {
  if (isoString === "") {
    return "";
  }
  const date = new Date(isoString);
  const pad = (n: number) => String(n).padStart(2, "0");
  return `${String(date.getFullYear())}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}T${pad(date.getHours())}:${pad(date.getMinutes())}`;
}

export function PricingEditForm({ id }: PricingEditFormProps) {
  const { pricing, isLoading, error: fetchError } = usePricing(id);
  const { updatePricing, isUpdating, error: updateError } =
    useUpdatePricing(id);
  const [amount, setAmount] = useState<string | null>(null);
  const [validFrom, setValidFrom] = useState<string | null>(null);
  const [validTo, setValidTo] = useState<string | null>(null);

  if (isLoading) {
    return (
      <div className="max-w-lg space-y-4">
        <div className="h-10 animate-pulse rounded bg-muted" />
        <div className="h-10 animate-pulse rounded bg-muted" />
      </div>
    );
  }

  if (fetchError) {
    return <ErrorMessage error={toError(fetchError)} />;
  }

  if (pricing === null) {
    return <ErrorMessage error={new Error("価格が見つかりません")} />;
  }

  const currentAmount = amount ?? String(pricing.amount);
  const currentValidFrom = validFrom ?? toDatetimeLocal(pricing.validFrom);
  const currentValidTo = validTo ?? toDatetimeLocal(pricing.validTo ?? "");

  function handleSubmit(event: React.FormEvent<HTMLFormElement>) {
    event.preventDefault();
    if (pricing === null) {
      return;
    }
    updatePricing({
      amount: Number(currentAmount),
      validFrom: new Date(currentValidFrom).toISOString(),
      ...(currentValidTo !== "" && {
        validTo: new Date(currentValidTo).toISOString(),
      }),
      version: pricing.version,
    });
  }

  return (
    <form onSubmit={handleSubmit} className="max-w-lg space-y-4">
      {updateError !== null && updateError !== undefined && (
        <ErrorMessage error={toError(updateError)} />
      )}

      <div className="space-y-2">
        <label htmlFor="amount" className="text-sm font-medium">
          金額
        </label>
        <input
          id="amount"
          type="number"
          value={currentAmount}
          onChange={(e) => {
            setAmount(e.target.value);
          }}
          required
          min={1}
          step="0.01"
          className="w-full rounded-md border px-3 py-2"
        />
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div className="space-y-2">
          <label htmlFor="validFrom" className="text-sm font-medium">
            有効開始日時
          </label>
          <input
            id="validFrom"
            type="datetime-local"
            value={currentValidFrom}
            onChange={(e) => {
              setValidFrom(e.target.value);
            }}
            required
            className="w-full rounded-md border px-3 py-2"
          />
        </div>

        <div className="space-y-2">
          <label htmlFor="validTo" className="text-sm font-medium">
            有効終了日時（任意）
          </label>
          <input
            id="validTo"
            type="datetime-local"
            value={currentValidTo}
            onChange={(e) => {
              setValidTo(e.target.value);
            }}
            className="w-full rounded-md border px-3 py-2"
          />
        </div>
      </div>

      <div className="flex gap-2">
        <Button type="submit" disabled={isUpdating}>
          {isUpdating ? "更新中..." : "更新"}
        </Button>
        <Button asChild variant="outline">
          <Link to="/pricings/$id" params={{ id }}>
            キャンセル
          </Link>
        </Button>
      </div>
    </form>
  );
}

