      wrapper: createWrapper(),
    });

    expect(result.current.pricing).toEqual({
      id: "pr-1",
      productId: "p-1",
      level: "STD",
      areaCode: "JP",
      amount: 1500,
      validFrom: "2025-01-01T00:00:00Z",
      validTo: null,
      version: 0,
    });
  });
});

