import { useState } from "react";
import { Button } from "@/components/ui/button";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { ConfirmDialog } from "@/components/confirm-dialog";
import { ErrorMessage } from "@/components/error-message";
import { toError } from "@/lib/utils";
import { usePricingList } from "@/features/pricing/hooks/use-pricing-list";
import { useDeletePricing } from "@/features/pricing/hooks/use-delete-pricing";
import { LEVEL_LABELS } from "@/features/pricing/types/pricing-level";
import type { PricingLevel } from "@/features/pricing/types/pricing-level";
import { PricingFormDialog } from "@/features/product/components/pricing-form-dialog";

interface ProductPricingListProps {
  readonly productId: string;
}

export function ProductPricingList({ productId }: ProductPricingListProps) {
  const { pricings, isLoading } = usePricingList(0, 100, productId);
  const { deletePricing, isDeleting, error: deleteError } = useDeletePricing();
  const [isCreateOpen, setIsCreateOpen] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState<{
    id: string;
    version: number;
  } | null>(null);

  return (
    <div className="space-y-3">
      <div className="flex items-center justify-between">
        <h2 className="text-lg font-semibold">価格一覧</h2>
        <Button
          size="sm"
          onClick={() => {
            setIsCreateOpen(true);
          }}
        >
          価格を追加
        </Button>
      </div>

      {deleteError !== null && deleteError !== undefined && (
        <ErrorMessage error={toError(deleteError)} />
      )}

      {isLoading && (
        <div className="space-y-2">
          <div className="h-8 w-full animate-pulse rounded bg-muted" />
          <div className="h-8 w-full animate-pulse rounded bg-muted" />
        </div>
      )}

      {!isLoading && pricings.length === 0 && (
        <p className="text-sm text-muted-foreground">
          この商品の価格は登録されていません
        </p>
      )}

      {!isLoading && pricings.length > 0 && (
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>レベル</TableHead>
              <TableHead>エリア</TableHead>
              <TableHead className="text-right">金額</TableHead>
              <TableHead className="w-24" />
            </TableRow>
          </TableHeader>
          <TableBody>
            {pricings.map((pricing) => (
              <TableRow key={pricing.id}>
                <TableCell>
                  {LEVEL_LABELS[pricing.level as PricingLevel] ?? pricing.level}
                </TableCell>
                <TableCell>{pricing.areaCode}</TableCell>
                <TableCell className="text-right">
                  ¥{pricing.amount?.toLocaleString()}
                </TableCell>
                <TableCell>
                  <Button
                    variant="ghost"
                    size="xs"
                    onClick={() => {
                      setDeleteTarget({
                        id: pricing.id ?? "",
                        version: 0,
                      });
                    }}
                  >
                    削除
                  </Button>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      )}

      <PricingFormDialog
        isOpen={isCreateOpen}
        onClose={() => {
          setIsCreateOpen(false);
        }}
        productId={productId}
      />

      <ConfirmDialog
        isOpen={deleteTarget !== null}
        onClose={() => {
          setDeleteTarget(null);
        }}
        onConfirm={() => {
          if (deleteTarget !== null) {
            deletePricing(deleteTarget.id, deleteTarget.version);
            setDeleteTarget(null);
          }
        }}
        title="価格を削除"
        message="この価格を削除しますか？"
        confirmLabel="削除する"
        isLoading={isDeleting}
      />
    </div>
  );
}

