        className="py-1.5 text-xs italic text-muted-foreground/60"
        style={{ paddingLeft: `${String(depth * 1.25 + 2.25)}rem` }}
      >
        子カテゴリなし
      </div>
    );
  }

  return (
    <ul>
      {children.map((child) => (
        <CategoryTreeNode
          key={child.id}
          id={child.id ?? ""}
          name={child.name ?? ""}
          sortOrder={child.sortOrder ?? 0}
          depth={depth}
        />
      ))}
    </ul>
  );
}

