import org.jooq.Condition;
import org.jooq.DSLContext;
import org.jooq.impl.DSL;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageImpl;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Component;

/** Product クエリサービス実装。 */
@RequiredArgsConstructor
@Component
public class ProductQueryServiceImpl implements ProductQueryService {

  /** jOOQ DSL コンテキスト。 */
  private final DSLContext dsl;

  @Override
  public Page<ProductSummaryDto> findAll(final ProductListParam param, final Pageable pageable) {
    final Condition condition = buildCondition(param);

    final Integer totalCount =
        dsl.selectCount()
            .from(PRODUCTS)
            .where(condition)
            .fetchOne(0, Integer.class);
    final int total = totalCount != null ? totalCount : 0;

    final List<ProductSummaryDto> content =
        dsl.select(PRODUCTS.ID, PRODUCTS.NAME, PRODUCTS.STATUS, PRODUCTS.CATEGORY_ID)
            .from(PRODUCTS)
            .where(condition)
            .orderBy(PRODUCTS.CREATED_AT.desc())
            .limit(pageable.getPageSize())
            .offset((int) pageable.getOffset())
            .fetch(
                r ->
                    new ProductSummaryDto(
                        r.get(PRODUCTS.ID).toString(),
                        r.get(PRODUCTS.NAME),
                        r.get(PRODUCTS.STATUS),
                        r.get(PRODUCTS.CATEGORY_ID).toString()));

    return new PageImpl<>(content, pageable, total);
  }

  @Override
  public Optional<ProductDetailDto> findById(final String id) {
    final UUID uuid = UUID.fromString(id);
    return dsl.selectFrom(PRODUCTS)
        .where(PRODUCTS.ID.eq(uuid))
        .and(SoftDeleteCondition.notDeleted(PRODUCTS))
        .fetchOptional()
        .map(
            r ->
                new ProductDetailDto(
                    r.getId().toString(),
                    r.getName(),
                    r.getDescription(),
                    r.getCategoryId().toString(),
                    r.getSku(),
                    r.getStatus(),
                    r.getVersion()));
  }

  private Condition buildCondition(final ProductListParam param) {
    Condition condition = SoftDeleteCondition.notDeleted(PRODUCTS);
    if (param.categoryId() != null) {
      condition = condition.and(PRODUCTS.CATEGORY_ID.eq(UUID.fromString(param.categoryId())));
    }
    if (param.status() != null) {
      condition = condition.and(PRODUCTS.STATUS.eq(param.status()));
    }
    return condition;
  }
}

