/** Product クエリサービス実装。 */
@RequiredArgsConstructor
@Component
public class ProductQueryServiceImpl implements ProductQueryService {

  /** jOOQ DSL コンテキスト。 */
  private final DSLContext dsl;

  @Override
  public Page<ProductSummaryDto> findAll(final ProductListParam param, final Pageable pageable) {
    final Integer totalCount =
        dsl.selectCount()
            .from(PRODUCTS)
            .where(SoftDeleteCondition.notDeleted(PRODUCTS))
            .fetchOne(0, Integer.class);
    final int total = totalCount != null ? totalCount : 0;

    final List<ProductSummaryDto> content =
        dsl.select(PRODUCTS.ID, PRODUCTS.NAME, PRODUCTS.STATUS, PRODUCTS.CATEGORY_ID)
            .from(PRODUCTS)
            .where(SoftDeleteCondition.notDeleted(PRODUCTS))
            .orderBy(PRODUCTS.CREATED_AT.desc())
            .limit(pageable.getPageSize())
            .offset((int) pageable.getOffset())
            .fetch(
                r ->
                    new ProductSummaryDto(
                        r.get(PRODUCTS.ID).toString(),
                        r.get(PRODUCTS.NAME),
                        r.get(PRODUCTS.STATUS),
                        r.get(PRODUCTS.CATEGORY_ID).toString()));

    return new PageImpl<>(content, pageable, total);
  }

  @Override
  public Optional<ProductDetailDto> findById(final String id) {
    final UUID uuid = UUID.fromString(id);
    return dsl.selectFrom(PRODUCTS)
        .where(PRODUCTS.ID.eq(uuid))
        .and(SoftDeleteCondition.notDeleted(PRODUCTS))
        .fetchOptional()
        .map(
            r ->
                new ProductDetailDto(
                    r.getId().toString(),
                    r.getName(),
                    r.getDescription(),
                    r.getCategoryId().toString(),
                    r.getSku(),
                    r.getStatus(),
                    r.getVersion()));
  }
}

