            .orderBy(PRODUCTS.CREATED_AT.desc())
            .limit(pageable.getPageSize())
            .offset((int) pageable.getOffset())
            .fetch(
                r ->
                    new ProductSummaryDto(
                        r.get(PRODUCTS.ID).toString(),
                        r.get(PRODUCTS.NAME),
                        r.get(PRODUCTS.STATUS),
                        r.get(PRODUCTS.CATEGORY_ID).toString()));

    return new PageImpl<>(content, pageable, total);
  }

  @Override
  public Optional<ProductDetailDto> findById(final String id) {
    final UUID uuid = UUID.fromString(id);
    return dsl.selectFrom(PRODUCTS)
        .where(PRODUCTS.ID.eq(uuid))
        .and(SoftDeleteCondition.notDeleted(PRODUCTS))
        .fetchOptional()
        .map(
            r ->
                new ProductDetailDto(
                    r.getId().toString(),
                    r.getName(),
                    r.getDescription(),
                    r.getCategoryId().toString(),
                    r.getSku(),
                    r.getStatus(),
                    r.getVersion()));
  }

  private Condition buildCondition(final ProductListParam param) {
    Condition condition = SoftDeleteCondition.notDeleted(PRODUCTS);
