import { useQuery } from "@tanstack/react-query";
import { apiClient } from "@/lib/api-client";
import type { ProductSummaryResponse } from "@/api/openAPIDefinition.schemas";

interface ProductListResponse {
  readonly data: {
    readonly content: ProductSummaryResponse[];
    readonly totalPages: number;
    readonly totalElements: number;
  };
}

function buildUrl(
  page: number,
  size: number,
  sort: string,
  categoryId?: string,
  status?: string,
): string {
  const params = new URLSearchParams();
  params.set("page", String(page));
  params.set("size", String(size));
  params.set("sort", sort);
  if (categoryId !== undefined) {
    params.set("categoryId", categoryId);
  }
  if (status !== undefined) {
    params.set("status", status);
  }
  return `/api/v1/products?${params.toString()}`;
}

export function useProductList(
  page: number = 0,
  size: number = 20,
  categoryId?: string,
  status?: string,
) {
  const query = useQuery({
    queryKey: ["products", { page, size, categoryId, status }],
    queryFn: () =>
      apiClient<ProductListResponse>(
        buildUrl(page, size, "name,asc", categoryId, status),
      ),
  });

  return {
    products: (query.data?.data?.content ?? []) as ProductSummaryResponse[],
    totalPages: query.data?.data?.totalPages ?? 0,
    totalElements: query.data?.data?.totalElements ?? 0,
    isLoading: query.isLoading,
    error: query.error,
  };
}

