import { describe, expect, it, vi, beforeEach } from "vite-plus/test";
import { renderHook, waitFor } from "@testing-library/react";
import { createElement } from "react";
import type { ReactNode } from "react";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { useProductList } from "@/features/product/hooks/use-product-list";

vi.mock("@/lib/api-client", () => ({
  apiClient: vi.fn(),
}));

import { apiClient } from "@/lib/api-client";

function createWrapper() {
  const queryClient = new QueryClient({
    defaultOptions: { queries: { retry: false } },
  });

  return function Wrapper({ children }: { readonly children: ReactNode }) {
    return createElement(QueryClientProvider, { client: queryClient }, children);
  };
}

describe("useProductList", () => {
  beforeEach(() => {
    vi.resetAllMocks();
  });

  it("取得成功時に products を返す", async () => {
    const mockProducts = [
      { id: "1", name: "商品A", status: "DRAFT", categoryId: "cat-1" },
    ];

    vi.mocked(apiClient).mockResolvedValue({
      data: { content: mockProducts, totalPages: 1, totalElements: 1 },
      status: 200,
      headers: new Headers(),
    });

    const { result } = renderHook(() => useProductList(), {
      wrapper: createWrapper(),
    });

    await waitFor(() => {
      expect(result.current.isLoading).toBe(false);
    });

    expect(result.current.products).toEqual(mockProducts);
  });

  it("categoryId を渡すと URL に含まれる", async () => {
    vi.mocked(apiClient).mockResolvedValue({
      data: { content: [], totalPages: 0, totalElements: 0 },
      status: 200,
      headers: new Headers(),
    });

    renderHook(() => useProductList(0, 20, "cat-123"), {
      wrapper: createWrapper(),
    });

    await waitFor(() => {
      expect(vi.mocked(apiClient)).toHaveBeenCalled();
    });

    const url = vi.mocked(apiClient).mock.calls[0]?.[0] as string;
    expect(url).toContain("categoryId=cat-123");
  });
});

